catalog_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {

    if (isLoading || newValue == '') {
        return;
    }

    g_form.clearOptions('job_role');

    switch (newValue) {

        case 'it':
            g_form.addOption('job_role', 'software_engineer', 'Software Engineer');
            g_form.addOption('job_role', 'devops_engineer', 'DevOps Engineer');
            g_form.addOption('job_role', 'servicenow_developer', 'ServiceNow Developer');
            g_form.addOption('job_role', 'qa_engineer', 'QA Engineer');
            g_form.addOption('job_role', 'cloud_engineer', 'Cloud Engineer');
            break;

        case 'hr':
            g_form.addOption('job_role', 'hr_executive', 'HR Executive');
            g_form.addOption('job_role', 'talent_acquisition', 'Talent Acquisition');
            g_form.addOption('job_role', 'hr_manager', 'HR Manager');
            g_form.addOption('job_role', 'hr_business_partner', 'HR Business Partner');
            break;

        case 'finance':
            g_form.addOption('job_role', 'financial_analyst', 'Financial Analyst');
            g_form.addOption('job_role', 'accountant', 'Accountant');
            g_form.addOption('job_role', 'payroll_specialist', 'Payroll Specialist');
            g_form.addOption('job_role', 'finance_manager', 'Finance Manager');
            break;

        case 'sales':
            g_form.addOption('job_role', 'sales_executive', 'Sales Executive');
            g_form.addOption('job_role', 'account_manager', 'Account Manager');
            g_form.addOption('job_role', 'business_development', 'Business Development Executive');
            g_form.addOption('job_role', 'sales_manager', 'Sales Manager');
            break;

        case 'marketing':
            g_form.addOption('job_role', 'marketing_executive', 'Marketing Executive');
            g_form.addOption('job_role', 'digital_marketing', 'Digital Marketing Specialist');
            g_form.addOption('job_role', 'content_strategist', 'Content Strategist');
            g_form.addOption('job_role', 'seo_specialist', 'SEO Specialist');
            g_form.addOption('job_role', 'marketing_manager', 'Marketing Manager');
            break;

        case 'operations':
            g_form.addOption('job_role', 'operations_executive', 'Operations Executive');
            g_form.addOption('job_role', 'operations_manager', 'Operations Manager');
            g_form.addOption('job_role', 'logistics_coordinator', 'Logistics Coordinator');
            g_form.addOption('job_role', 'process_analyst', 'Process Analyst');
            break;
    }

}
